# site-wide patches applied to every Python interpreter startup.
#
# The iOS PyTorch build was compiled with USE_NUMPY=0 (rationale:
# binary size + ABI lock against bundled numpy). That makes
# `torch.from_numpy(arr)` and `tensor.numpy()` raise:
#
#     RuntimeError: PyTorch was compiled without NumPy support
#
# Both are heavily used inside transformers, diffusers, common
# training scripts, and probably every user notebook. Re-enabling
# them properly requires a PyTorch rebuild — out of scope for the
# bundled environment. We can install pure-Python equivalents that
# use the buffer-protocol path (`torch.frombuffer` / explicit byte
# copies), which give equivalent semantics for the call sites that
# actually matter.
#
# Caveats:
#   • The patched `from_numpy` does NOT share memory with the
#     numpy array — it copies once. Original behavior was zero-copy
#     in some paths; this is slightly slower but always correct.
#   • The patched `tensor.numpy()` likewise copies the storage.
#   • Both are no-ops if torch's native implementation already works
#     (i.e. if someone rebuilds torch with USE_NUMPY=1, we step aside).

import sys


def _install_numpy_bridge_shim() -> None:
    try:
        import torch
    except ImportError:
        return     # torch not installed — nothing to patch

    # Probe: does the native from_numpy work? If yes, don't patch.
    try:
        import numpy as np
        torch.from_numpy(np.array([1.0]))
        return     # native works — no shim needed
    except Exception:
        pass

    try:
        import numpy as np
    except ImportError:
        return     # no numpy on this build — nothing to bridge

    # ---- numpy → torch ------------------------------------------------
    _NP_TO_TORCH = {
        np.dtype("float32"): torch.float32,
        np.dtype("float16"): torch.float16,
        np.dtype("float64"): torch.float64,
        np.dtype("int8"):    torch.int8,
        np.dtype("uint8"):   torch.uint8,
        np.dtype("int16"):   torch.int16,
        np.dtype("int32"):   torch.int32,
        np.dtype("int64"):   torch.int64,
        np.dtype("bool"):    torch.bool,
    }

    def _from_numpy(arr):
        """Drop-in replacement for torch.from_numpy when torch was
        built with USE_NUMPY=0. Constructs a tensor by copying the
        numpy array's bytes through torch.frombuffer."""
        if not isinstance(arr, np.ndarray):
            raise TypeError(
                f"expected numpy.ndarray, got {type(arr).__name__}")
        np_dt = arr.dtype
        torch_dt = _NP_TO_TORCH.get(np_dt)
        if torch_dt is None:
            # Unsigned widths > 8: torch lacks native equivalents.
            # Cast through signed of same byte-width.
            if np_dt == np.uint16:
                arr = arr.astype(np.int32, copy=False)
                torch_dt = torch.int32
            elif np_dt == np.uint32:
                arr = arr.astype(np.int64, copy=False)
                torch_dt = torch.int64
            elif np_dt == np.uint64:
                arr = arr.astype(np.int64, copy=False)
                torch_dt = torch.int64
            elif np_dt.kind == "c":
                raise TypeError("complex dtypes not supported by torch shim")
            else:
                # Fallback: convert to float32. Loses precision for
                # exotic dtypes but better than crashing.
                arr = arr.astype(np.float32, copy=False)
                torch_dt = torch.float32
        contig = np.ascontiguousarray(arr)
        buf = bytearray(contig.tobytes())
        t = torch.frombuffer(buf, dtype=torch_dt).reshape(list(contig.shape))
        return t.clone()      # detach from the temp bytearray's lifetime

    # ---- torch → numpy ------------------------------------------------
    _TORCH_TO_NP = {
        torch.float32: np.dtype("float32"),
        torch.float16: np.dtype("float16"),
        torch.float64: np.dtype("float64"),
        torch.int8:    np.dtype("int8"),
        torch.uint8:   np.dtype("uint8"),
        torch.int16:   np.dtype("int16"),
        torch.int32:   np.dtype("int32"),
        torch.int64:   np.dtype("int64"),
        torch.bool:    np.dtype("bool"),
    }

    def _tensor_to_numpy(self):
        """Drop-in replacement for tensor.numpy()."""
        if self.is_cuda:
            self = self.cpu()
        # Detach from autograd so reading .data is safe.
        t = self.detach().contiguous()
        np_dt = _TORCH_TO_NP.get(t.dtype)
        if np_dt is None:
            # bfloat16 / complex / etc. — bounce via float32.
            t = t.to(torch.float32)
            np_dt = np.dtype("float32")
        # Pull raw bytes via the storage and copy into a new numpy array.
        try:
            stg = t.untyped_storage()
            buf = bytes(stg)[:t.numel() * t.element_size()]
        except AttributeError:
            buf = bytes(t.numpy().tobytes())  # would recurse, but only if storage missing
        return np.frombuffer(buf, dtype=np_dt).copy().reshape(list(t.shape))

    # ---- Install -----------------------------------------------------
    torch.from_numpy = _from_numpy
    # `tensor.numpy()` is a C method — assigning to torch.Tensor.numpy
    # replaces it for all instances. Python tolerates this for Tensor
    # because it's defined as a regular method on the class object.
    try:
        torch.Tensor.numpy = _tensor_to_numpy
    except Exception:
        pass    # some torch versions lock the slot; from_numpy alone is the bigger win

    sys.modules.setdefault("__codebench_numpy_shim_installed__", True)


def _install_metal_matmul_bridge() -> None:
    """Route large 2-D float32 matmuls through the iPad GPU via the
    Swift @_cdecl Metal bridge. No-op outside CodeBench (where the
    Swift symbols aren't linked into the running executable).

    Lives here in sitecustomize so any python script — user notebook,
    transformers, hand-rolled training loop — picks it up before
    importing torch."""
    try:
        import _torch_metal_bridge
    except ImportError:
        return     # bridge module not bundled in this build
    _torch_metal_bridge.install(verbose=False)


try:
    _install_numpy_bridge_shim()
except Exception as e:
    # Never let the shim break Python startup.
    import sys as _sys
    print(f"[sitecustomize] numpy/torch bridge shim failed: {e}", file=_sys.stderr)

try:
    _install_metal_matmul_bridge()
except Exception as e:
    import sys as _sys
    print(f"[sitecustomize] metal matmul bridge failed: {e}", file=_sys.stderr)
